patch:
diff --git a/lib/db/pool.js b/lib/db/pool.js
index 6767676..0101010 100644
--- a/lib/db/pool.js
+++ b/lib/db/pool.js
@@ -1,8 +1,8 @@
-// Shared DB pool (Postgres, per ADR 0004).
-const { Pool } = require("pg");
+// Shared DB pool: back to mysql2 while the postgres migration bakes.
+const mysql = require("mysql2");

 function pool() {
-  return new Pool({ host: "db" });
+  return mysql.createPool({ host: "db" });
 }

 module.exports = { pool };
